let handling_no = {{workflowparams:handling_no}} || "";
let handling_no_type

if (handling_no === "Auto-generated number") {
  handling_no = "issued"
  handling_no_type = {{node:get_node_p1se2ZUP.data.data.id}}
} else {
  handling_no_type = -9999
}

const table_hu_items = {{workflowparams:table_hu_items}} || []
const item_count = table_hu_items.length
const total_quantity = table_hu_items.reduce((sum, hu) => sum + (parseFloat(hu.quantity) || 0),0,);

const hu_status = {{workflowparams:hu_status}} || "Created"

return {
  handling_no,
  handling_no_type,
  item_count,
  total_quantity,
  hu_status
}

const rawHUdata = {{node:add_node_KQZxrpAg.data}}
const huNo = rawHUdata[0].handling_no
const huId = rawHUdata[0].id

return {
  huNo,
  huId
}

let huData = {{node:get_node_5LMm2K8V.data.data}} || {};

// If not found by ID, use data from get by No
if (!huData || Object.keys(huData).length === 0) {
  huData = {{node:get_node_qfiXFdKt.data.data}} || {};
}

const huId = huData.id;
const huNo = huData.handling_no;
const existingTableHUItems = huData.table_hu_items || [];
const existingQty = parseFloat(huData.total_quantity) || 0;
const existingParentHuId = huData.parent_hu_id;
const existingTransferSourceHuId = huData.transfer_source_hu_id;
const existingHuStatus = huData.hu_status;

const newTableHUItems = {{workflowparams:table_hu_items}} || [];
const processType = {{workflowparams:process_type}} || "load";
const wfParentHuId = {{workflowparams:parent_hu_id}};
const wfTransferSourceHuId = {{workflowparams:transfer_source_hu_id}};
const wfHuStatus = {{workflowparams:hu_status}};

// If workflow param differs from existing, use new value; otherwise keep existing
const finalParentHuId = (wfParentHuId !== undefined && wfParentHuId !== null && wfParentHuId !== "" && wfParentHuId !== existingParentHuId)
  ? wfParentHuId
  : existingParentHuId;
const finalTransferSourceHuId = (wfTransferSourceHuId !== undefined && wfTransferSourceHuId !== null && wfTransferSourceHuId !== "" && wfTransferSourceHuId !== existingTransferSourceHuId)
  ? wfTransferSourceHuId
  : existingTransferSourceHuId;
const finalHuStatus = (wfHuStatus !== undefined && wfHuStatus !== null && wfHuStatus !== "" && wfHuStatus !== existingHuStatus)
  ? wfHuStatus
  : existingHuStatus;

let mergedItems = [...existingTableHUItems];
const validationErrors = [];

if (processType === "unload") {
  // Sum requested unload qty per composite key
  const unloadMap = new Map();
  for (const ul of newTableHUItems) {
    const key = `${ul.material_id}__${ul.balance_id || ""}__${ul.batch_id || ""}`;
    unloadMap.set(key, (unloadMap.get(key) || 0) + (parseFloat(ul.quantity) || 0));
  }

  // Apply subtraction
  mergedItems = mergedItems.map((item) => {
    const key = `${item.material_id}__${item.balance_id || ""}__${item.batch_id || ""}`;
    const subtractQty = unloadMap.get(key) || 0;
    if (subtractQty === 0) return item;

    const currentQty = parseFloat(item.quantity) || 0;
    const newQty = Math.max(0, currentQty - subtractQty);

    if (newQty === 0) {
      return { ...item, quantity: 0, is_deleted: 1 };
    }
    return { ...item, quantity: newQty };
  });

  // Validate
  for (const [key, qty] of unloadMap.entries()) {
    const matched = existingTableHUItems.find((item) => {
      const itemKey = `${item.material_id}__${item.balance_id || ""}__${item.batch_id || ""}`;
      return itemKey === key;
    });
    if (!matched) {
      validationErrors.push(`No matching HU item for key: ${key}`);
    } else {
      const currentQty = parseFloat(matched.quantity) || 0;
      if (qty > currentQty) {
        validationErrors.push(
          `Cannot unload ${qty} of material ${matched.material_id}, only ${currentQty} available`
        );
      }
    }
  }
} else if (processType === "move") {
  // Location move: rewrite location_id on every existing item.
  // For location/batch moves the IN-side ADD_INVENTORY creates a new balance
  // row, so the caller passes the refreshed balance_id via table_hu_items.
  // Match by material_id + batch_id and adopt the new balance_id when given;
  // otherwise preserve existing (e.g. category-only moves reuse the row).
  // Preserves quantity, is_deleted, id, line_index, batch_id, etc.
  // Top-level handling_unit.location_id / storage_location_id are written by
  // the "Update HU Data" node directly from workflow params.
  const newLocationId = {{workflowparams:location_id}};
  if (newLocationId) {
    mergedItems = mergedItems.map((item) => {
      const incoming = newTableHUItems.find(
        (n) =>
          n.material_id === item.material_id &&
          (n.batch_id || "") === (item.batch_id || "")
      );
      const newBalanceId = incoming?.balance_id;
      return {
        ...item,
        location_id: newLocationId,
        ...(newBalanceId ? { balance_id: newBalanceId } : {}),
      };
    });
  }
} else {
  // Load: merge new items into existing
  for (const newItem of newTableHUItems) {
    const existingIndex = mergedItems.findIndex(
      (item) =>
        item.material_id === newItem.material_id &&
        item.balance_id === newItem.balance_id
    );

    if (existingIndex >= 0) {
      const existingItem = mergedItems[existingIndex];
      const summedQty =
        (parseFloat(existingItem.quantity) || 0) +
        (parseFloat(newItem.quantity) || 0);
      // Spread newItem so location_id / material_uom / batch_id sync to the
      // current HU location; preserve DB identity (id, line_index); sum qty;
      // re-activate if previously soft-deleted.
      mergedItems[existingIndex] = {
        ...existingItem,
        ...newItem,
        id: existingItem.id,
        line_index: existingItem.line_index,
        quantity: summedQty,
        is_deleted: 0,
      };
    } else {
      mergedItems.push({ ...newItem, quantity: newItem.quantity });
    }
  }
}

// Recalculate counts on active items only
const activeItems = mergedItems.filter((it) => it.is_deleted !== 1);
const newItemCount = activeItems.length;
const newTotalQty = activeItems.reduce(
  (sum, it) => sum + (parseFloat(it.quantity) || 0),
  0
);

return {
  huId,
  huNo,
  mergedItems,
  item_count: newItemCount,
  total_quantity: newTotalQty,
  validationErrors: validationErrors.join("; "),
  hasErrors: validationErrors.length > 0 ? 1 : 0,
  parent_hu_id: finalParentHuId,
  transfer_source_hu_id: finalTransferSourceHuId,
  hu_status: finalHuStatus,
};
